eliminated_showstopper = function(ep_number){
   bakeoff |&gt;
    filter(episode == ep_number, str_detect(result, "Eliminated")) |&gt;
    summarize(
      n = n(),
      showstopper = if_else(n &gt; 0, 
                            str_flatten(showstopper, collapse = ","), "none")) |&gt;
    pull(showstopper)
}

